898	static int
899	find_base14_index(const char *name)
900	{
901		if (!strcmp(name, "Courier")) return 0;
902		if (!strcmp(name, "Courier-Oblique")) return 1;
903		if (!strcmp(name, "Courier-Bold")) return 2;
904		if (!strcmp(name, "Courier-BoldOblique")) return 3;
905		if (!strcmp(name, "Helvetica")) return 4;
906		if (!strcmp(name, "Helvetica-Oblique")) return 5;
907		if (!strcmp(name, "Helvetica-Bold")) return 6;
908		if (!strcmp(name, "Helvetica-BoldOblique")) return 7;
909		if (!strcmp(name, "Times-Roman")) return 8;
910		if (!strcmp(name, "Times-Italic")) return 9;
911		if (!strcmp(name, "Times-Bold")) return 10;
912		if (!strcmp(name, "Times-BoldItalic")) return 11;
913		if (!strcmp(name, "Symbol")) return 12;
914		if (!strcmp(name, "ZapfDingbats")) return 13;
915		return -1;
916	}
917	
918	fz_font *
919	fz_new_base14_font(fz_context *ctx, const char *name)
920	{
921		const unsigned char *data;
922		int size;
923		int x = find_base14_index(name);
924		if (x >= 0)
925		{
926			if (ctx->font->base14[x])
927				return fz_keep_font(ctx, ctx->font->base14[x]);
928			data = fz_lookup_base14_font(ctx, name, &size);
929			if (data)
930			{
931				ctx->font->base14[x] = fz_new_font_from_memory(ctx, name, data, size, 0, 1);
932				ctx->font->base14[x]->flags.is_serif = (name[0] == 'T'); /* Times-Roman */
933				/* Ideally we should not embed base14 fonts by default, but we have to
934				 * allow it for now until we have written code in pdf-device to output
935				 * base14s in a 'special' manner. */
936				fz_set_font_embedding(ctx, ctx->font->base14[x], 1);
937				return fz_keep_font(ctx, ctx->font->base14[x]);
938			}
939		}
940		fz_throw(ctx, FZ_ERROR_ARGUMENT, "cannot find builtin font with name '%s'", name);
941	}
