943	fz_font *
944	fz_new_cjk_font(fz_context *ctx, int ordering)
945	{
946		const unsigned char *data;
947		int size, index;
948		fz_font *font;
949		if (ordering >= 0 && ordering < (int)nelem(ctx->font->cjk))
950		{
951			if (ctx->font->cjk[ordering])
952				return fz_keep_font(ctx, ctx->font->cjk[ordering]);
953			data = fz_lookup_cjk_font(ctx, ordering, &size, &index);
954			if (data)
955				font = fz_new_font_from_memory(ctx, NULL, data, size, index, 0);
956			else
957				font = fz_load_system_cjk_font(ctx, "SourceHanSerif", ordering, 1);
958			/* FIXME: Currently the builtin one at least will be set to embed. Is that right? */
959			if (font)
960			{
961				font->flags.cjk = 1;
962				font->flags.cjk_lang = ordering;
963				ctx->font->cjk[ordering] = font;
964				return fz_keep_font(ctx, ctx->font->cjk[ordering]);
965			}
966		}
967		fz_throw(ctx, FZ_ERROR_ARGUMENT, "cannot find builtin CJK font");
968	}
