196		fz_glyph *glyph = NULL;
197		fz_pixmap *pix = NULL;
198		int size, fill, yy;
199		unsigned char *orig_sp = sp;
200	
201		fz_var(glyph);
202		fz_var(pix);
203	
204		fz_try(ctx)
205		{
206			/* We start out by allocating space as large as the pixmap.
207			 * If we need more than that give up on using RLE. We can
208			 * never hope to beat the pixmap for really small sizes. */
209			if (w <= 6 || w * h < RLE_THRESHOLD)
