211	
212			size = h * w;
213			fill = h * sizeof(int);
214			glyph = Memento_label(fz_malloc(ctx, sizeof(fz_glyph) + size), "fz_glyph(8)");
215			FZ_INIT_STORABLE(glyph, 1, fz_drop_glyph_imp);
216			glyph->x = x;
217			glyph->y = y;
218			glyph->w = w;
219			glyph->h = h;
220			glyph->pixmap = NULL;
221			if (h == 0)
222			{
223				glyph->size = 0;
224				break;
225			}
226			for (yy=0; yy < h; yy++)
227			{
228				int nonblankfill = fill;
229				int nonblankfill_end = fill;
230				int linefill = fill;
231				int ww = w;
232				do
233				{
234					int code;
235					int len = ww;
236					int needed;
237					unsigned char *ep;
238					switch (*sp)
239					{
240					case 0:
241						if (len > 0x1000)
242							len = 0x1000;
243						ep = sp+len;
244						while (++sp != ep && *sp == 0);
245						code = 1;
246						len -= ep-sp;
247						ww -= len;
248						needed = fill + 1 + (len > 0x40);
249						break;
250					case 255:
251						if (len > 0x800)
252							len = 0x800;
253						ep = sp+len;
254						while (++sp != ep && *sp == 255);
255						code = 2;
256						len -= ep-sp;
257						ww -= len;
258						needed = fill + 1 + (len > 0x20);
259						break;
260					default:
261					{
262						unsigned char c;
263						if (len > 0x800)
264							len = 0x800;
265						ep = sp+len;
266						while (++sp != ep && (c = *sp) != 255 && c != 0);
267						len -= ep-sp;
268						ww -= len;
269						needed = fill + 1 + len + (len > 0x20);
270						code = 3;
271					}
272					}
273					if (needed > size)
274						goto try_pixmap;
275					if (code == 1)
276					{
277						if (len > 0x40)
278							glyph->data[fill++] = ((len-1)>>6)<<2;
279						glyph->data[fill++] = 1 | (((len-1)&63)<<2);
280					}
281					else
282					{
283						if (len > 0x20)
284							glyph->data[fill++] = ((len-1)>>5)<<2;
285						nonblankfill = fill;
286						glyph->data[fill++] = code | (((len-1)&31)<<3);
287						if (code == 3)
288						{
289							memcpy(&glyph->data[fill], sp - len, len);
290							fill += len;
291						}
292						nonblankfill_end = fill;
293					}
294				}
295				while (ww > 0);
296				if (nonblankfill_end == linefill)
297				{
298					((int *)(glyph->data))[yy] = -1;
299					fill = linefill;
300				}
301				else
302				{
303					glyph->data[nonblankfill] |= 4;
304					fill = nonblankfill_end;
305					((int *)(glyph->data))[yy] = linefill;
306				}
307				sp += span - w;
