313			}
314			glyph->size = size;
315			break;
316	
317			/* Nasty use of a goto here, but it saves us having to exit
318			 * and reenter the try context, and this routine is speed
319			 * critical. */
320	try_pixmap:
321			glyph = Memento_label(fz_realloc(ctx, glyph, sizeof(fz_glyph)), "fz_glyph(8r)");
