376				int nonblankfill = fill;
377				int nonblankfill_end = fill;
378				int linefill = fill;
379				int ww = w;
380				int bit = 0x80;
381				do
382				{
383					int len = 0;
384					int needed;
385					int b = *sp & bit;
386					bit >>= 1;
387					if (bit == 0)
388						bit = 0x80, sp++;
389					ww--;
390					if (b == 0)
391					{
392						while (ww > 0 && len < 0xfff && (*sp & bit) == 0)
393						{
394							bit >>= 1;
395							if (bit == 0)
396								bit = 0x80, sp++;
397							len++;
398							ww--;
399						}
400						needed = fill + (len >= 0x40) + 1;
401						if (needed > size)
402							goto try_pixmap;
403						if (len >= 0x40)
404							glyph->data[fill++] = (len>>6)<<2;
405						glyph->data[fill++] = 1 | ((len&63)<<2);
406					}
407					else
408					{
409						while (ww > 0 && len < 0x7ff && (*sp & bit) != 0)
410						{
411							bit >>= 1;
412							if (bit == 0)
413								bit = 0x80, sp++;
414							len++;
415							ww--;
416						}
417						needed = fill + (len >= 0x20) + 1;
418						if (needed > size)
419							goto try_pixmap;
420						if (len >= 0x20)
421							glyph->data[fill++] = (len>>5)<<2;
422						nonblankfill = fill;
423						glyph->data[fill++] = 2 | ((len&31)<<3);
424						nonblankfill_end = fill;
425					}
426				}
427				while (ww > 0);
428				if (nonblankfill_end == linefill)
429				{
430					((int *)(glyph->data))[yy] = -1;
431					fill = linefill;
432				}
433				else
434				{
435					glyph->data[nonblankfill] |= 4;
436					fill = nonblankfill_end;
437					((int *)(glyph->data))[yy] = linefill;
438				}
439				sp += span - (w>>3);
440			}
441			if (fill != size)
442			{
443				glyph = fz_realloc(ctx, glyph, sizeof(fz_glyph) + fill);
444				size = fill;
445			}
446			glyph->size = size;
447			break;
448	
449			/* Nasty use of a goto here, but it saves us having to exit
450			 * and reenter the try context, and this routine is speed
451			 * critical. */
452	try_pixmap:
453			glyph = fz_realloc(ctx, glyph, sizeof(fz_glyph));
454			FZ_INIT_STORABLE(glyph, 1, fz_drop_glyph_imp);
455			pix = fz_new_pixmap_from_1bpp_data(ctx, x, y, w, h, orig_sp, span);
456			glyph->x = pix->x;
457			glyph->y = pix->y;
458			glyph->w = pix->w;
459			glyph->h = pix->h;
460			glyph->size = fz_pixmap_size(ctx, pix);
461			glyph->pixmap = pix;
462		}
463		fz_catch(ctx)
464		{
465			fz_drop_pixmap(ctx, pix);
466			fz_free(ctx, glyph);
467			fz_rethrow(ctx);
468		}
469	
470		return glyph;
471	}
